import React, { useEffect, useState } from 'react';
import PropTypes from 'prop-types';
import { useTranslation } from 'react-i18next';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { getLegalDocByPath, PUBLIC_BASE as BASE, SUPPORT_EMAIL } from '../../constants/legalUrls';
import { markLegalRouteVisit } from '../../services/sessionDetectionService';

// Standalone, public (no sign-in) renderer for the legal markdown documents.
// Mounted before the auth providers in App, keyed off window.location.pathname,
// so /legal/privacy and /legal/terms are reachable without an account.

// `node` is destructured out of every override so react-markdown's AST node
// object never leaks into `...props` and onto the DOM. Keep it — do not remove.
export function getSafeMarkdownHref(href) {
  if (!href) return undefined;
  return /^(https?:|mailto:|#)/i.test(href) ? href : undefined;
}

const markdownComponents = {
  h1: ({ node, children, ...props }) => (
    <h1 className="text-3xl font-bold text-sky-400 mt-2 mb-4" {...props}>{children}</h1>
  ),
  h2: ({ node, children, ...props }) => (
    <h2 className="text-xl font-semibold text-sky-300 mt-8 mb-3" {...props}>{children}</h2>
  ),
  h3: ({ node, children, ...props }) => (
    <h3 className="text-lg font-medium text-sky-200 mt-6 mb-2" {...props}>{children}</h3>
  ),
  p: ({ node, children, ...props }) => (
    <p className="text-slate-200 leading-relaxed mb-4" {...props}>{children}</p>
  ),
  ul: ({ node, children, ...props }) => (
    <ul className="list-disc pl-6 mb-4 space-y-1 text-slate-200" {...props}>{children}</ul>
  ),
  ol: ({ node, children, ...props }) => (
    <ol className="list-decimal pl-6 mb-4 space-y-1 text-slate-200" {...props}>{children}</ol>
  ),
  li: ({ node, children, ...props }) => <li className="text-slate-200" {...props}>{children}</li>,
  a: ({ node, href, children, ...props }) => {
    const safeHref = getSafeMarkdownHref(href);
    // Open external links in a new tab; let in-page anchors (#section) scroll.
    const isExternal = safeHref && !safeHref.startsWith('#');
    return (
      // Spread props first so the security attributes below always win, even if
      // a future react-markdown/plugin passes its own target/rel.
      <a
        href={safeHref}
        className="text-sky-400 underline hover:text-sky-300"
        {...props}
        {...(isExternal ? { target: '_blank', rel: 'noopener noreferrer' } : {})}
      >
        {children}
      </a>
    );
  },
  strong: ({ node, children, ...props }) => (
    <strong className="font-semibold text-slate-100" {...props}>{children}</strong>
  ),
  blockquote: ({ node, children, ...props }) => (
    <blockquote className="border-l-4 border-sky-500/50 pl-4 italic text-slate-300 my-4" {...props}>
      {children}
    </blockquote>
  ),
  table: ({ node, children, ...props }) => (
    <div className="overflow-x-auto mb-4">
      <table className="w-full text-sm text-left border-collapse" {...props}>{children}</table>
    </div>
  ),
  th: ({ node, children, ...props }) => (
    <th className="border border-slate-600 px-3 py-2 bg-slate-700 text-sky-200" {...props}>{children}</th>
  ),
  td: ({ node, children, ...props }) => (
    <td className="border border-slate-600 px-3 py-2 text-slate-200 align-top" {...props}>{children}</td>
  ),
  hr: ({ node, ...props }) => <hr className="border-slate-700 my-6" {...props} />,
  code: ({ node, children, ...props }) => (
    <code className="bg-slate-700 text-sky-200 rounded px-1 py-0.5 text-sm" {...props}>{children}</code>
  ),
  // Fenced code blocks render as <pre><code>; style the <pre> so it isn't unthemed
  // (no fenced blocks in the docs today, but keeps the theme consistent if added).
  pre: ({ node, children, ...props }) => (
    <pre className="bg-slate-700 rounded p-4 overflow-x-auto mb-4 text-sm" {...props}>{children}</pre>
  ),
  // Strip images: the legal docs don't use them, and allowing arbitrary src URLs
  // from future markdown edits would be an unreviewed external-content boundary.
  img: ({ node }) => null,
};

export function LegalScreen({ pathname }) {
  const { t } = useTranslation('common');
  // App is the only production caller and always passes a matched pathname; we
  // deliberately don't fall back to window.location here. The !doc branch below
  // is a guard for direct/standalone use, exercised by LegalScreen.test.js.
  const doc = getLegalDocByPath(pathname);
  const [content, setContent] = useState(null);
  const [status, setStatus] = useState('loading'); // 'loading' | 'loaded' | 'error'

  useEffect(() => {
    if (doc) {
      markLegalRouteVisit();
    }
  }, [doc]);

  useEffect(() => {
    if (!doc) return undefined;
    const previousTitle = document.title;
    document.title = `${t(doc.titleKey)} · Sport Wizard`;
    return () => {
      document.title = previousTitle;
    };
  }, [doc, t]);

  useEffect(() => {
    if (!doc) return undefined;
    let active = true;
    const controller = new AbortController();
    // Reach the error state instead of spinning forever on a stalled connection.
    const timeout = setTimeout(() => controller.abort(), 10000);
    setStatus('loading');
    fetch(`${BASE}/legal/${doc.markdownFile}`, { signal: controller.signal })
      .then((res) => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.text();
      })
      .then((text) => {
        if (!active) return;
        setContent(text);
        setStatus('loaded');
      })
      .catch((err) => {
        if (active) {
          console.error('[LegalScreen] fetch failed', err);
          setStatus('error');
        }
      })
      .finally(() => clearTimeout(timeout));
    return () => {
      active = false;
      clearTimeout(timeout);
      controller.abort();
    };
  }, [doc]);

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col items-center font-sans px-4 py-6 sm:py-10">
      <div className="w-full max-w-3xl">
        <div className="mb-6">
          {/* BASE is empty (relative '/') on Vercel/local; on native this screen
              is never mounted (legal links open the system browser), so the
              relative href is always browser-resolved here. */}
          <a href={`${BASE}/`} className="text-sky-400 hover:text-sky-300 text-sm">
            &larr; Sport Wizard
          </a>
        </div>
        <main className="bg-slate-800 rounded-lg shadow-xl p-5 sm:p-8">
          {!doc && (
            <div className="text-slate-200">
              <h1 className="text-2xl font-bold text-sky-400 mb-3">{t('legal.notFoundTitle')}</h1>
              <p>
                {t('legal.notFoundBody')}{' '}
                <a href={`${BASE}/`} className="text-sky-400 underline hover:text-sky-300">
                  {t('legal.notFoundReturn')}
                </a>
                .
              </p>
            </div>
          )}
          {doc && status === 'loading' && <p className="text-slate-400">{t('legal.loading')}</p>}
          {doc && status === 'error' && (
            <p className="text-slate-300">
              {t('legal.loadError')}{' '}
              <a href={`mailto:${SUPPORT_EMAIL}`} className="text-sky-400 underline">
                {SUPPORT_EMAIL}
              </a>
              .
            </p>
          )}
          {doc && status === 'loaded' && (
            <ReactMarkdown remarkPlugins={[remarkGfm]} components={markdownComponents}>
              {content}
            </ReactMarkdown>
          )}
        </main>
      </div>
    </div>
  );
}

LegalScreen.propTypes = {
  pathname: PropTypes.string.isRequired,
};
